import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the size of the buffer to prevent buffer overflow
        char[] buffer = new char[Math.min(name.length(), 10)];

        // Copying characters from 'name' to 'buffer'
        for (int i = 0; i < buffer.length; i++) {
            buffer[i] = name.charAt(i);
        }

        // Truncating the string properly
        String truncatedName = new String(buffer);

        System.out.println("Hello, " + truncatedName);
    }
}

